var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"미리네 씨, 여기예요…! 다행히 모두 무사하셨군요……!","JPN":"マリさん、ここです……！　よかった、無事だったんですね……！","ENG":"Ms. Mi Rinae, over here...! Thank goodness, you're all safe...!","TWN":"宓璃奈，這裡…！幸好大家都平安無事……！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아하하, 내 한 발 늦었나?","JPN":"あはは、一足遅れちゃったんか？","ENG":"Ahaha, guess I showed up a bit late?","TWN":"啊哈哈，我是不是慢了一步？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"종자님께서 곧 수송기를 보낸다고 하셨어요. 조금만 기다리면 시니어님을 모시고……","JPN":"従者様がもうすぐ輸送機を送るそうです。あと少しで、シニアを連れて……","ENG":"Squire said a transport will be dispatched soon. Once it arrives, we'll bring the Senior...","TWN":"手下說很快就會派運輸機過來。再等一下就能把Senior接……"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"으음?","JPN":"ん？","ENG":"Mm?","TWN":"嗯？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"저… 혹시 시니어님께서는…….","JPN":"あの……もしかして、シニアは……","ENG":"Wait... the Senior...","TWN":"……Senior……"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"시니어 칸께서는 운명을 달리하셨습니다.","JPN":"シニア・カンは永い眠りにつかれました。","ENG":"Senior Khan has passed away.","TWN":"Senior已經離世。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"하지만 돌아가시기 전에 자신의 모든 권한을 시타 아가씨께 맡기셨어요.","JPN":"ですが、亡くなる前にご自身のすべての権限をシータお嬢様に託されました。","ENG":"But before his death, he entrusted all his authority to Lady Sita.","TWN":"但是在去世之前，他將自己所有的權限都移交悉多小姐。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"OPR_ADMIN_WHITE_NULL","text":{"KOREA":"따라서 지금은 시타 아가씨께서 캄파멘토의 시니어입니다.","JPN":"よって、現在はシータお嬢様がカンパメントのシニアです。","ENG":"As of now, Lady Sita is the Senior of Campamento.","TWN":"因此，現在是悉多小姐就是坎帕門托的Senior。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그, 그렇군요…….","JPN":"そ、そうなんですね……","ENG":"I-I see...","TWN":"原，原來如此……"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"자자, 다들 얼굴 좀 펴이소.","JPN":"まあまあ、みんな湿気た顔せんとき。","ENG":"Come on, everyone, don't look so down.","TWN":"好了好了，大家都笑一笑。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"슬퍼하는 건, 나중에 해도 충분합니데이.","JPN":"悲しむのは後でも十分やろ。","ENG":"There'll be plenty of time to grieve later.","TWN":"傷心的事，晚點再說吧。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"살아 있는 사람은, 살아가는 게 먼저 아이겠습니까.","JPN":"生きてる人間は、生きなあかんねん。","ENG":"For the living, survival comes first.","TWN":"活著的人，活下去才是最重要的，不是嗎？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"지금은… 이 섬에서 빠져나가가, 캄파멘토의 상황을 알리는 게 먼저입니다.","JPN":"今は…この島を抜け出して、カンパメントの状況を知らせることが優先や。","ENG":"Right now, escaping this island and reporting to Campamento is the priority.","TWN":"現在……首先是要從這個島上逃出去，將坎帕門托的情況告知大家。"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"그러니까……","JPN":"だから……","ENG":"So...","TWN":"所以……"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"지, 지진……?","JPN":"じ、地震……？","ENG":"A-an earthquake...?","TWN":"地，地震……？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"설마, 또 데몰리션 웜이 나타나는 걸까요?","JPN":"まさか、またデモリッションワームが現れるのでしょうか？","ENG":"Don't tell me it's another Demolition Worm!","TWN":"難道又是爆破蠕蟲？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"아이다! 이건 지진이 아니고, 공간 자체가 떨리고 있는기다……!","JPN":"ちゃう！　これは地震じゃない、空間自体が揺れてるんや……！","ENG":"No! This isn't a quake. The space itself is shaking...!","TWN":"哎呀！這不是地震，而是空間本身在震動……！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L34_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"공간이 떨린다고요?","JPN":"空間が揺れる？","ENG":"Space is shaking?","TWN":"空間在震動嗎？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"찬란하게 빛나는 태양이 나무뿌리에 가려, 그 빛을 잃어버리게 될 때.","JPN":"燦々と輝く太陽が木の根に隠れ、その光を失う時。","ENG":"When the radiant sun is veiled by roots, its light fading away...","TWN":"當璀璨耀眼的陽光被樹根遮蔽而失去光芒之時，"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"하늘이 갈라지며 땅과 구름이 맞닿는 곳, 어딘가 황금의 도시가 모습을 드러내고.","JPN":"天が切り裂かれ、地と雲が交わる場所、そのどこかに黄金の都市が姿を現し、","ENG":"The heavens will split open, and where earth and cloud meet, a golden city will appear.","TWN":"天空將會裂開，在大地與雲彩交會的地方，黃金城將現身。  "},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"그곳, 황금향이 남긴 유산이 수많은 이들을 구하게 되리라.","JPN":"かの地、黄金郷が残した遺産が多くの者を救うであろう。","ENG":"There, the Golden Vale's Legacy will save countless lives.","TWN":"黃金城留下的寶藏，將拯救無數的人。  "},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"전설대로라면… 지금이 그 때일지도 몰라요…….","JPN":"伝説通りなら……今がその時なのかもしれません……","ENG":"If the legend is true... this might be that moment...","TWN":"如果傳說是真的……現在可能就是那個時候……"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"뭐, 뭐라고예?","JPN":"な、なんやと？","ENG":"W-what did you say?","TWN":"你，你說什麼？"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"두 분 다 거기서 피하세요……!","JPN":"二人とも、そこから逃げて……！","ENG":"Both of you, get back...!","TWN":"你們兩個，快從那裡躲開……！"},"stage":{"bg":"CITY_JUNGLE","slots":{"L":null,"C":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"이, 이게 뭐고? 진짜로 대균열에서 나무뿌리가 뻗어나왔다고……?","JPN":"な、何やこれ？　ホンマに大亀裂から木の根が伸びてきたで……？","ENG":"W-what the–? Roots are spreading out from the Grand Dimension Crevice itself?!","TWN":"這，這是啥？真的有樹根從大峽谷中竄出來……？"},"stage":{"bg":"OMEN_CAMPAMENTO_01","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_SURPRISE"}}}},{"id":"L48_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"그, 그럼 이제 우리는 어쩌죠?","JPN":"こ、これから、一体どうなるのでしょう？","ENG":"Then what do we do now...?","TWN":"那，那我們現在該怎麼辦呢？"},"stage":{"bg":"OMEN_CAMPAMENTO_01","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"AURA_ADMIN_NULL_BODY","text":{"KOREA":"전설대로 세계가 멸망하게 되는 걸까요?","JPN":"伝説通り、世界は滅んでしまうんですか？","ENG":"Is the world really going to end, just like the legend?","TWN":"難道真的會如傳說中那樣，世界將要毀滅嗎？"},"stage":{"bg":"OMEN_CAMPAMENTO_01","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"STAR_HUNTER_NULL_NULL","text":{"KOREA":"글쎄다? 그래도 도망칠 수 있는 데까지는 도망쳐 봐야 하지 않겠나?","JPN":"さあ？　でも逃げられるとこまでは逃げてみるしかないやろ？","ENG":"Who knows? Either way, we run as far as we can.","TWN":"不知道呢？不過還是要儘量逃遠點吧。"},"stage":{"bg":"OMEN_CAMPAMENTO_01","slots":{"L":{"char_id":"STAR_HUNTER_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"AURA_ADMIN_NULL_BODY","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"L12_1","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L43_1","slots":{"L":null,"C":null,"R":{"char_id":"OPR_ADMIN_WHITE_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"CAMPAMENTO_ADMIN_NULL_ON","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"L21_1","slots":{"L":null,"C":{"char_id":"CAMPAMENTO_ADMIN_NULL_ON","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};